import React from 'react';

function Education({ data }) {
  if (!data) return null;

  return (
    <section id="education" className="py-16 bg-white">
      <div className="max-w-6xl mx-auto px-4">
        <h2 className="text-4xl font-bold text-gray-800 mb-12 text-center">Education</h2>
        <div className="space-y-6">
          {data.map((edu) => (
            <div key={edu.id} className="border-l-4 border-blue-600 bg-gray-50 p-6 rounded-r-lg">
              <h3 className="text-2xl font-bold text-gray-800">{edu.degree}</h3>
              <p className="text-blue-600 font-semibold text-lg mt-2">{edu.institution}</p>
              <p className="text-gray-600 mt-2">{edu.period}</p>
              {edu.details && <p className="text-gray-600">{edu.details}</p>}
              {edu.location && <p className="text-gray-600">{edu.location}</p>}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Education;
